}

#[derive(Debug, Default)]
struct CliArgs {
    port: u16,
    agent_name: String,
    env_file: Option<String>,
    env_overrides: Vec<(String, String)>,
    mock_quota_specs: Vec<String>,
    model_ref: Option<String>,
    probe_mode: Option<String>,
    probe_timeout_secs: u64,
    quota_min_req: Option<u64>,
    quota_min_tok: Option<u64>,
    ignore_process_env: bool,
    exe_name: String,
}

#[derive(Debug, Clone)]
struct OllamaEmulatorState {
    lifecycle: Option<literbike::env_facade_parity::ModelmuxMvpLifecycle>,
    quota_selection: Option<literbike::env_facade_parity::ModelmuxMvpQuotaSelection>,
    quota_state: Vec<QuotaState>,
    provider_state: Vec<ProviderState>,
    models: Vec<OllamaModel>,
}

#[derive(Debug, Clone)]
struct QuotaState {
    slot_id: String,
    model_ref: String,
    free: bool,
    remaining_requests: Option<u64>,
    remaining_tokens: Option<u64>,
    selectors: Vec<String>,
}

#[derive(Debug, Clone)]
struct ProviderState {
    family: String,
    base_url: Option<String>,
    model: Option<String>,
    api_key_env: Option<String>,
    confidence: u8,
}

impl Default for OllamaEmulatorState {
    fn default() -> Self {
        Self {
            lifecycle: None,
            quota_selection: None,
            quota_state: vec![],
            provider_state: vec![],
            models: vec![],
        }
    }
}

#[tokio::main]
async fn main() {
    env_logger::Builder::from_env(env_logger::Env::default().default_filter_or("info")).init();

    let exe_name = std::env::args()
        .next()
        .unwrap_or_else(|| "ollama_emulator".to_string());
    let exe_basename = std::path::Path::new(&exe_name)
        .file_name()
        .and_then(|s| s.to_str())
        .unwrap_or("ollama_emulator")
        .to_string();

    log::info!("Ollama Emulator started (exe: {})", exe_basename);

    let mut args_vec: Vec<String> = std::env::args().skip(1).collect();
    if args_vec.first().map(|s| s.as_str()) == Some("serve") {
        log::info!("'ollama serve' command detected, starting server");
        args_vec.remove(0);
    }

    let args = match parse_args(args_vec, &exe_basename) {
        Ok(args) => args,
        Err(msg) => {
            eprintln!("{msg}");
            eprintln!("{}", usage(&exe_basename));
            std::process::exit(2);
        }
    };

    log::info!("Starting Ollama Emulator on port {}", args.port);

    let (lifecycle, quota_selection, quota_state, provider_state) = initialize_state(&args);
    let models = build_models_from_lifecycle(&lifecycle, &quota_state);

    let state = Arc::new(RwLock::new(OllamaEmulatorState {
        lifecycle,
        quota_selection,
        quota_state,
        provider_state,
        models,
    }));

    run_http_server(args.port, state).await;
}

