fn parse_env_assignment(line: &str) -> Result<(String, String), String> {
    if let Some(eq) = line.find('=') {
        let key = line[..eq].trim().to_string();
        let value = strip_matching_quotes(line[eq + 1..].trim());
        if key.is_empty() {
            return Err("empty key in env assignment".to_string());
        }
        Ok((key, value.to_string()))
    } else {
        Err("missing '=' in env assignment".to_string())
    }
}

fn strip_matching_quotes(s: &str) -> &str {
    if s.len() >= 2 {
        let bytes = s.as_bytes();
        let first = bytes[0];
        let last = bytes[s.len() - 1];
        if (first == b'"' && last == b'"') || (first == b'\'' && last == b'\'') {
            return &s[1..s.len() - 1];
        }
    }
    s
}

fn initialize_state(args: &CliArgs) -> (
    Option<literbike::env_facade_parity::ModelmuxMvpLifecycle>,
    Option<literbike::env_facade_parity::ModelmuxMvpQuotaSelection>,
    Vec<QuotaState>,
    Vec<ProviderState>,
) {
    let mut merged_env = if args.ignore_process_env {
        BTreeMap::new()
    } else {
        std::env::vars().collect()
    };

    if let Some(path) = args.env_file.as_deref() {
        if let Ok(data) = std::fs::read_to_string(path) {
            for line in data.lines() {
                let line = line.trim();
                if line.is_empty() || line.starts_with('#') {
                    continue;
                }
                let line = line.strip_prefix("export ").unwrap_or(line).trim();
                if let Ok((k, v)) = parse_env_assignment(line) {
                    merged_env.insert(k, v);
                }
            }
        }
    }

    for (k, v) in &args.env_overrides {
        merged_env.insert(k.clone(), v.clone());
    }

    let env_pairs: Vec<(String, String)> = merged_env.into_iter().collect();
    let model_ref = args.model_ref.clone().unwrap_or_else(|| "/free/moonshotai/kimi-k2".to_string());
    let cfg = Some(PragmaticUnifiedPortConfig {
        agent_name: args.agent_name.clone(),
        unified_port: args.port,
    });

    let mut probe_cache = GenericApiModelsProbeCache::default();
    let curl_probe = if args
        .probe_mode
        .as_deref()
        .map(|m| m.eq_ignore_ascii_case("curl"))
        .unwrap_or(false)
    {
        Some(CurlModelsProbe {
            timeout_secs: if args.probe_timeout_secs == 0 { 3 } else { args.probe_timeout_secs },
        })
    } else {
        None
    };

    match run_modelmux_mvp_lifecycle_with_options(
        env_pairs,
        &model_ref,
        cfg.as_ref(),
        curl_probe.as_ref().map(|p| p as &dyn GenericApiModelsProbe),
        Some(&mut probe_cache),
    ) {
        Ok(lifecycle) => {
            log::info!("{}", format_modelmux_mvp_lifecycle_line(&lifecycle));

            let provider_state = project_provider_state(&lifecycle);
            for ps in &provider_state {
                log::info!("Provider: family={} base_url={:?} model={:?}", 
                    ps.family, ps.base_url, ps.model);
            }

            let (quota_selection, quota_state) = if !args.mock_quota_specs.is_empty() {
                let records: Vec<MockQuotaInventoryRecord> = args
                    .mock_quota_specs
                    .iter()
                    .filter_map(|s| parse_mock_quota_spec(s).ok())
                    .collect();

                if !records.is_empty() {
                    let adapter = StaticMockQuotaInventoryAdapter { records };
                    if let Ok(inventory) = adapter.load_quota_inventory() {
                        let selection = evaluate_modelmux_mvp_quota_inventory(&lifecycle, &inventory);
                        log::info!("{}", format_modelmux_mvp_quota_selection_line(&selection));

                        let dry_run = if args.quota_min_req.is_some() || args.quota_min_tok.is_some() {
                            let mut opts = QuotaDrainerDryRunOptions::default();
                            if let Some(v) = args.quota_min_req {
                                opts.min_remaining_requests = v;
                            }
                            if let Some(v) = args.quota_min_tok {
                                opts.min_remaining_tokens = v;
                            }
                            run_modelmux_quota_drainer_dry_run_with_options(&lifecycle, &inventory, &opts)
                        } else {
                            run_modelmux_quota_drainer_dry_run(&lifecycle, &inventory)
                        };

                        log::info!("{}", format_quota_drainer_dry_run_line(&dry_run));

                        let qstate = project_quota_state(&selection);
                        (Some(selection), qstate)
                    } else {
                        (None, vec![])
                    }
                } else {
                    (None, vec![])
                }
            } else {
                (None, vec![])
            };

            (Some(lifecycle), quota_selection, quota_state, provider_state)
        }
        Err(err) => {
            log::warn!("Failed to initialize lifecycle: {:?}", err);
            (None, None, vec![], vec![])
        }
    }
}

fn project_provider_state(lifecycle: &literbike::env_facade_parity::ModelmuxMvpLifecycle) -> Vec<ProviderState> {
    let mut providers = Vec::new();

    for binding in &lifecycle.provider_api_keys {
        let family = binding.family_hint
            .map(|f| format!("{:?}", f))
            .unwrap_or_else(|| "unknown".to_string());

        let mut base_url = None;
        let mut model = None;
        for entry in &lifecycle.env_profile.entries {
            if entry.role == Some(literbike::provider_facade_models::EnvVarRole::BaseUrl) && 
               entry.key.to_lowercase().contains(&family.to_lowercase()) {
                base_url = Some(entry.value.clone());
            }
            if entry.role == Some(literbike::provider_facade_models::EnvVarRole::Model) &&
               entry.key.to_lowercase().contains(&family.to_lowercase()) {
                model = Some(entry.value.clone());
            }
        }

        providers.push(ProviderState {
            family,
            base_url,
            model,
            api_key_env: Some(binding.env_key.clone()),
            confidence: binding.confidence,
        });
    }

    providers
}

fn project_quota_state(
    selection: &literbike::env_facade_parity::ModelmuxMvpQuotaSelection,
) -> Vec<QuotaState> {
    selection
        .candidates
        .iter()
        .map(|c| QuotaState {
            slot_id: c.slot.slot_id.clone(),
            model_ref: c.slot.model_id.clone(),
            free: c.slot.free,
            remaining_requests: c.slot.remaining_requests,
            remaining_tokens: c.slot.remaining_tokens,
            selectors: c.slot.selectors.clone(),
        })
        .collect()
}

fn build_models_from_lifecycle(
    lifecycle: &Option<literbike::env_facade_parity::ModelmuxMvpLifecycle>,
    quota_state: &[QuotaState],
) -> Vec<OllamaModel> {
    let mut models = Vec::new();

    if let Some(lc) = lifecycle {
        let model_name = lc.route.upstream_model_id.clone();
        let quota_info = quota_state.iter().find(|q| q.model_ref == model_name);

        let details = OllamaModelDetails {
            parent_model: "".to_string(),
            format: "ollama-emulator".to_string(),
            family: lc.route.selectors.first().cloned().unwrap_or_else(|| "unknown".to_string()),
            families: lc.route.dsel_tags.clone(),
            parameter_size: quota_info
                .and_then(|q| q.remaining_tokens)
                .map(|t| format!("{}", t))
                .unwrap_or_else(|| "unknown".to_string()),
            quantization_level: if quota_info.map(|q| q.free).unwrap_or(false) {
                "free-tier".to_string()
            } else {
                "paid-tier".to_string()
            },
        };

        models.push(OllamaModel {
            name: model_name.clone(),
            model: model_name,
            modified_at: chrono::Utc::now().to_rfc3339(),
            size: 0,
            digest: format!("sha256:{}", lc.route.route_key),
            details,
        });
    }

    for quota in quota_state {
        if !models.iter().any(|m| m.name == quota.model_ref) {
            models.push(OllamaModel {
                name: quota.model_ref.clone(),
                model: quota.model_ref.clone(),
                modified_at: chrono::Utc::now().to_rfc3339(),
                size: 0,
                digest: format!("sha256:{}", quota.slot_id),
                details: OllamaModelDetails {
                    parent_model: "".to_string(),
                    format: "ollama-emulator".to_string(),
                    family: quota.selectors.first().cloned().unwrap_or_else(|| "quota".to_string()),
                    families: quota.selectors.clone(),
                    parameter_size: quota
                        .remaining_tokens
                        .map(|t| format!("{}", t))
                        .unwrap_or_else(|| "unknown".to_string()),
                    quantization_level: if quota.free {
                        "free-tier".to_string()
                    } else {
                        "paid-tier".to_string()
                    },
                },
            });
        }
    }

    models
}

fn parse_mock_quota_spec(s: &str) -> Result<MockQuotaInventoryRecord, String> {
    let mut parts = s.split("::");
    let slot_id = parts.next().ok_or("missing slot_id")?.to_string();
    let rest = parts.next().ok_or("missing model_ref_or_id")?.to_string();

    let mut record = MockQuotaInventoryRecord {
        slot_id,
        model_ref_or_id: rest.clone(),
        base_url: None,
        enabled: true,
        healthy: true,
        free: false,
        selectors: vec![],
        metadata: BTreeMap::new(),
        notes: vec![],
        remaining_requests: None,
        remaining_tokens: None,
    };

    if let Some(semi) = rest.find(';') {
        record.model_ref_or_id = rest[..semi].to_string();
        for token in rest[semi + 1..].split(';') {
            if let Some(v) = token.strip_prefix("req=") {
                record.remaining_requests = v.parse().ok();
            } else if let Some(v) = token.strip_prefix("tok=") {
                record.remaining_tokens = v.parse().ok();
            } else if token == "free" {
                record.free = true;
            } else if token == "paid" {
                record.free = false;
            } else if let Some(v) = token.strip_prefix("selector=") {
                record.selectors.push(v.to_string());
            } else if let Some(v) = token.strip_prefix("note=") {
                record.notes.push(v.to_string());
            }
        }
    }

    Ok(record)
}

struct CurlModelsProbe {
    timeout_secs: u64,
}

impl GenericApiModelsProbe for CurlModelsProbe {
    fn probe_models_capability(
        &self,
        _base_url: &str,
        candidate_urls: &[String],
    ) -> Option<GenericApiModelsProbeClassification> {
        for url in candidate_urls {
            let output = std::process::Command::new("curl")
                .arg("-sS")
                .arg("-m")
                .arg(self.timeout_secs.to_string())
                .arg("-o")
                .arg("-")
                .arg("-w")
                .arg("\n__CURL_STATUS__:%{http_code}")
                .arg("-H")
                .arg("accept: application/json")
                .arg(url)
                .output()
                .ok()?;

            let stdout = String::from_utf8_lossy(&output.stdout);
            let (body, status) = parse_curl_status_output(&stdout);
            let status = status.unwrap_or(0);

            if matches!(status, 200 | 401 | 403) {
                let body_lc = body.to_ascii_lowercase();
                let family_hint = if body_lc.contains("anthropic") || body_lc.contains("claude") {
                    Some(ProviderFamily::AnthropicCompatible)
                } else if body_lc.contains("gemini") || body_lc.contains("google") {
                    Some(ProviderFamily::GeminiNative)
                } else {
                    Some(ProviderFamily::OpenAiCompatible)
                };

                return Some(GenericApiModelsProbeClassification {
                    api_kind: literbike::env_facade_parity::ApiKind::ModelProvider,
                    family_hint,
                    confidence: if status == 200 { 92 } else { 78 },
                    reason: format!("curl models probe HTTP {}", status),
                    matched_probe_url: Some(url.clone()),
                });
            }
        }
        None
    }
}

fn parse_curl_status_output(stdout: &str) -> (String, Option<u16>) {
    let marker = "\n__CURL_STATUS__:";
    if let Some(idx) = stdout.rfind(marker) {
        let body = stdout[..idx].to_string();
        let code_str = stdout[(idx + marker.len())..].trim();
        let code = code_str.parse::<u16>().ok();
        (body, code)
    } else {
        (stdout.to_string(), None)
    }
}

async fn run_http_server(port: u16, state: Arc<RwLock<OllamaEmulatorState>>) {
    use tokio::io::{AsyncBufReadExt, AsyncWriteExt, BufReader};
    use tokio::net::{TcpListener, TcpStream};

    let addr = format!("0.0.0.0:{}", port);
    let listener = TcpListener::bind(&addr).await.expect("Failed to bind");
    log::info!("Ollama Emulator listening on {}", addr);

    loop {
        let (stream, addr) = match listener.accept().await {
            Ok(v) => (v, addr.clone()),
            Err(e) => {
                log::error!("Accept error: {}", e);
                continue;
            }
        };

        let state = Arc::clone(&state);
        tokio::spawn(async move {
            if let Err(e) = handle_connection(stream, state).await {
                log::error!("Connection error from {}: {}", addr, e);
            }
        });
    }
}

async fn handle_connection(stream: TcpStream, state: Arc<RwLock<OllamaEmulatorState>>) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    use tokio::io::{AsyncBufReadExt, AsyncWriteExt, BufReader};

    let mut reader = BufReader::new(stream);
    let mut request_line = String::new();
    reader.read_line(&mut request_line).await?;

    let parts: Vec<&str> = request_line.trim().split_whitespace().collect();
    if parts.len() < 2 {
        return Ok(());
    }

    let method = parts[0];
    let path = parts[1];

    let mut headers = BTreeMap::new();
    let mut content_length: usize = 0;
    loop {
        let mut line = String::new();
        reader.read_line(&mut line).await?;
        if line.trim().is_empty() {
            break;
        }
        if let Some(colon) = line.find(':') {
            let key = line[..colon].trim().to_lowercase();
            let value = line[colon + 1..].trim().to_string();
            if key == "content-length" {
                content_length = value.parse().unwrap_or(0);
            }
            headers.insert(key, value);
        }
    }

    let mut body = String::new();
    if content_length > 0 {
        let mut buf = vec![0u8; content_length];
        use tokio::io::AsyncReadExt;
        reader.read_exact(&mut buf).await?;
        body = String::from_utf8_lossy(&buf).to_string();
    }

    let (status, response_body) = route_request(method, path, &body, &state).await;

    let mut writer = reader.get_mut();
    let response = format!(
        "HTTP/1.1 {} {}\r\nContent-Type: application/json\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
        status,
        status_text(status),
        response_body.len(),
        response_body
    );
    writer.write_all(response.as_bytes()).await?;
    writer.flush().await?;

    Ok(())
}

fn status_text(status: u16) -> &'static str {
    match status {
        200 => "OK",
        400 => "Bad Request",
        404 => "Not Found",
        500 => "Internal Server Error",
        _ => "Unknown",
    }
}

async fn route_request(
    method: &str,
    path: &str,
    body: &str,
    state: &Arc<RwLock<OllamaEmulatorState>>,
) -> (u16, String) {
    match (method, path) {
        ("GET", "/api/version") => {
            let response = OllamaVersionResponse {
                version: "0.1.0-ollama-emulator".to_string(),
            };
            (200, serde_json::to_string(&response).unwrap())
        }
        ("GET", "/api/tags") => {
            let state = state.read().await;
            let response = OllamaTagsResponse {
                models: state.models.clone(),
            };
            (200, serde_json::to_string(&response).unwrap())
        }
        // USER MODEL TREE API - discovers models from all configured XXXXX_API_KEY env vars
        ("GET", "/v1/models") | ("GET", "/models") => {
            let models = discover_user_models();
            let response = OpenAiModelsResponse {
                object: "list".to_string(),
                data: models,
            };
            (200, serde_json::to_string(&response).unwrap())
        }
        ("POST", "/api/chat") => {
            handle_chat(body, state).await
        }
        ("POST", "/api/generate") => {
            handle_generate(body, state).await
        }
        ("POST", "/api/show") => {
            handle_show(body, state).await
        }
        ("GET", "/health") => {
            let state = state.read().await;
            let ready = state.lifecycle.is_some();
            let status = if ready { 200 } else { 503 };
            let response = serde_json::json!({
                "status": if ready { "ready" } else { "not_ready" },
                "has_lifecycle": ready,
                "providers": state.provider_state.len(),
                "quotas": state.quota_state.len(),
            });
            (status, response.to_string())
        }
        ("GET", "/metrics") => {
            let state = state.read().await;
            let metrics = build_metrics(&state);
            (200, metrics)
        }
        _ => {
            (404, r#"{"error":"not found"}"#.to_string())
        }
    }
}

/// Discover models from all configured provider API keys in environment
/// This is the USER MODEL TREE API - shows what models the user has access to
fn discover_user_models() -> Vec<OpenAiModel> {
    let mut all_models = Vec::new();

    // Scan environment for XXXXX_API_KEY patterns
    for (key_var, _) in env::vars() {
        if key_var.ends_with("_API_KEY") && !key_var.contains("_SEARCH_") {
            let provider = key_var.trim_end_matches("_API_KEY").to_lowercase();

            // Add provider's default model pattern
            all_models.push(OpenAiModel {
                id: format!("{}/{}-model", provider, provider),
                object: "model".to_string(),
                created: chrono::Utc::now().timestamp() as u64,
                owned_by: provider.clone(),
            });

            // Add generic model patterns for this provider
            all_models.push(OpenAiModel {
                id: format!("{}/default", provider),
                object: "model".to_string(),
                created: chrono::Utc::now().timestamp() as u64,
                owned_by: provider.clone(),
            });
        }
    }

    all_models
}

fn build_metrics(state: &OllamaEmulatorState) -> String {
    let mut lines = Vec::new();
    lines.push("# HELP ollama_providers_total Number of configured providers".to_string());
    lines.push("# TYPE ollama_providers_total gauge".to_string());
    lines.push(format!("ollama_providers_total {}", state.provider_state.len()));

    lines.push("# HELP ollama_quotas_total Number of quota slots".to_string());
    lines.push("# TYPE ollama_quotas_total gauge".to_string());
    lines.push(format!("ollama_quotas_total {}", state.quota_state.len()));

    let free_count = state.quota_state.iter().filter(|q| q.free).count();
    let paid_count = state.quota_state.len() - free_count;

    lines.push("# HELP ollama_quotas_free Number of free tier quotas".to_string());
    lines.push("# TYPE ollama_quotas_free gauge".to_string());
    lines.push(format!("ollama_quotas_free {}", free_count));

    lines.push("# HELP ollama_quotas_paid Number of paid tier quotas".to_string());
    lines.push("# TYPE ollama_quotas_paid gauge".to_string());
    lines.push(format!("ollama_quotas_paid {}", paid_count));

    let total_tokens: u64 = state.quota_state.iter()
        .filter_map(|q| q.remaining_tokens)
        .sum();
    lines.push("# HELP ollama_tokens_remaining Total remaining tokens".to_string());
    lines.push("# TYPE ollama_tokens_remaining gauge".to_string());
    lines.push(format!("ollama_tokens_remaining {}", total_tokens));

    lines.join("\n")
}

async fn handle_chat(
    body: &str,
    state: &Arc<RwLock<OllamaEmulatorState>>,
) -> (u16, String) {
    let request: OllamaChatRequest = match serde_json::from_str(body) {
        Ok(v) => v,
        Err(e) => {
            return (400, serde_json::json!({"error": format!("invalid request: {}", e)}).to_string());
        }
    };

    log::info!("Chat request for model: {}", request.model);

    let state = state.read().await;
    let model_name = if let Some(ref lc) = state.lifecycle {
        lc.route.upstream_model_id.clone()
    } else {
        request.model.clone()
    };

    let quota_info = state.quota_state.iter().find(|q| q.model_ref == model_name);
    let provider_info = state.provider_state.first();

    let response = OllamaChatResponse {
        model: model_name,
        message: OllamaMessage {
            role: "assistant".to_string(),
            content: format!(
                "[Ollama Emulator] Chat routed via modelmux.\n\
                 Model: {}\n\
                 Provider: {:?}\n\
                 Quota: {}\n\
                 Tags: {:?}",
                request.model,
                provider_info.map(|p| &p.family),
                quota_info.map(|q| if q.free { "free" } else { "paid" }).unwrap_or("none"),
                quota_info.map(|q| &q.selectors).unwrap_or(&vec![]),
            ),
        },
        done: true,
    };

    (200, serde_json::to_string(&response).unwrap())
}

async fn handle_generate(
    body: &str,
