}

async fn handle_show(
    body: &str,
    state: &Arc<RwLock<OllamaEmulatorState>>,
) -> (u16, String) {
    let request: OllamaShowRequest = match serde_json::from_str(body) {
        Ok(v) => v,
        Err(e) => {
            return (400, serde_json::json!({"error": format!("invalid request: {}", e)}).to_string());
        }
    };

    let state = state.read().await;

    let model = state.models.iter().find(|m| m.name == request.model || m.model == request.model);

    let details = if let Some(m) = model {
        m.details.clone()
    } else {
        OllamaModelDetails {
            parent_model: "".to_string(),
            format: "gguf".to_string(),
            family: "ollama-emulator".to_string(),
            families: vec!["ollama-emulator".to_string()],
            parameter_size: "unknown".to_string(),
            quantization_level: "unknown".to_string(),
        }
    };

    let response = OllamaShowResponse {
        license: "MIT".to_string(),
        modelfile: format!("# Modelfile for {}\n# Projected from modelmux lifecycle", request.model),
        parameters: "".to_string(),
        template: "{{ .Prompt }}".to_string(),
        details,
    };

    (200, serde_json::to_string(&response).unwrap())
}

